class IoTController:
    def __init__(self, pin_onboard=2, active_high=True):
        self.active_high = active_high
        self.pin = machine.Pin(pin_onboard, machine.Pin.OUT)
        self.turn_off()

    def turn_on(self):
        self.pin.value(1 if self.active_high else 0)

    def turn_off(self):
        self.pin.value(0 if self.active_high else 1)

    def toggle(self):
        self.pin.value(0 if self.pin.value() else 1)

    def status(self):
        v = self.pin.value()
        is_on = bool(v) if self.active_high else (not bool(v))
        return {"on": bool(is_on)}

