def connect_wifi(ssid, password, hostname="esp32-ws", timeout_s=15):
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    try:
        wlan.config(dhcp_hostname=hostname)
    except:
        pass
    if not wlan.isconnected():
        wlan.connect(ssid, password)
        start = time.ticks_ms()
        while not wlan.isconnected():
            if time.ticks_diff(time.ticks_ms(), start) > timeout_s * 1000:
                raise RuntimeError("WiFi connect timeout")
            time.sleep_ms(200)
    return wlan.ifconfig()

async def main(ssid=None, password=None, port=80, ws_path="/ws", pin=2):
    if ssid and password:
        ipcfg = connect_wifi(ssid, password)
        print("WiFi:", ipcfg)
    controller = IoTController(pin_onboard=pin, active_high=True)
    server = WebSocketServer(host="0.0.0.0", port=port, path=ws_path, controller=controller)
    await server.start()
    print("WebSocket server on ws://%s:%d%s" % (network.WLAN(network.STA_IF).ifconfig()[0], port, ws_path))
    while True:
        await asyncio.sleep(3600)

